index.styles:
* { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'Hiragino Kaku Gothic ProN', 'Hiragino Sans', Meiryo, sans-serif; color: #333; line-height: 1.8; background: #feffff; }
    .hero { background: linear-gradient(160deg, #1b5e20 0%, #388e3c 45%, #2e7d32 100%); color: #fff; padding: 88px 20px 72px; text-align: center; }
    .hero-inner { max-width: 720px; margin: 0 auto; }
    .hero-icon { width: 120px; height: 120px; border-radius: 28px; box-shadow: 0 8px 32px rgba(0,0,0,0.2); margin-bottom: 1.25rem; }
    .hero .eyebrow { display: inline-block; background: rgba(255,255,255,0.15); border: 1px solid rgba(255,255,255,0.25); border-radius: 100px; padding: 6px 18px; font-size: 0.8rem; margin-bottom: 1rem; }
    .hero h1 { font-size: 2.4rem; font-weight: 800; margin-bottom: 0.25rem; }
    .hero h1 small { display: block; font-size: 1.1rem; font-weight: 500; opacity: 0.95; margin-top: 0.35rem; }
    .hero .desc { font-size: 1rem; max-width: 560px; margin: 1.25rem auto 0; opacity: 0.95; }
    .badge-row { display: flex; flex-wrap: wrap; justify-content: center; gap: 10px; margin-top: 1.75rem; }
    .badge { background: rgba(255,255,255,0.2); border-radius: 8px; padding: 8px 14px; font-size: 0.85rem; font-weight: 600; }
    section { padding: 72px 20px; }
    section:nth-child(even) { background: #f8faf8; }
    .container { max-width: 960px; margin: 0 auto; }
    .section-title { font-size: 1.55rem; font-weight: 700; text-align: center; margin-bottom: 0.5rem; }
    .section-subtitle { text-align: center; color: #666; font-size: 0.95rem; margin-bottom: 2.5rem; }
    .features-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 18px; }
    .feature-card { background: #fff; border-radius: 14px; padding: 24px; border: 1px solid #e8f5e9; box-shadow: 0 1px 4px rgba(0,0,0,0.04); }
    .feature-card .icon { font-size: 1.8rem; margin-bottom: 0.6rem; }
    .feature-card h3 { font-size: 1rem; margin-bottom: 0.4rem; color: #2e7d32; }
    .feature-card p { font-size: 0.88rem; color: #555; }
    .games-list { display: grid; grid-template-columns: repeat(auto-fit, minmax(140px, 1fr)); gap: 12px; }
    .game-pill { background: #fff; border: 2px solid #c8e6c9; border-radius: 12px; padding: 16px 12px; text-align: center; font-weight: 700; font-size: 0.9rem; color: #33691e; }
    .screenshot-gallery { display: flex; flex-wrap: wrap; justify-content: center; gap: 20px; }
    .screenshot-item { flex: 0 1 200px; max-width: 220px; border-radius: 16px; overflow: hidden; box-shadow: 0 4px 20px rgba(0,0,0,0.1); background: #fff; transition: transform 0.2s, box-shadow 0.2s; }
    .screenshot-item:hover { transform: translateY(-4px); box-shadow: 0 8px 28px rgba(0,0,0,0.14); }
    .screenshot-item img { width: 100%; height: auto; display: block; }
    .screenshot-label { padding: 10px 12px; font-size: 0.8rem; color: #555; text-align: center; font-weight: 600; }
    .cta-section { text-align: center; }
    .cta-section .btn { display: inline-block; background: #4CAF50; color: #fff; text-decoration: none; padding: 14px 28px; border-radius: 10px; font-weight: 700; margin: 6px; }
    .cta-section .btn.secondary { background: #FFC107; color: #333; }
    .cta-section .micro { margin-top: 1rem; font-size: 0.82rem; color: #888; }
    .cta-section .store-badges { display: flex; justify-content: center; gap: 16px; margin-top: 1.5rem; flex-wrap: wrap; }
    .cta-section .store-badge { display: inline-block; background: #333; color: #fff; padding: 12px 24px; border-radius: 8px; font-size: 0.9rem; font-weight: 600; text-decoration: none; transition: background 0.2s, transform 0.15s; }
    .cta-section .store-badge:hover { background: #111; transform: translateY(-1px); }
    footer { text-align: center; padding: 32px 20px; border-top: 1px solid #eee; font-size: 0.85rem; color: #888; }
    footer a { color: #4CAF50; text-decoration: none; }
    footer .links a { margin: 0 12px; }

